class SessionManager private constructor() {

    companion object {
        private const val SESSION_DURATION_MILLIS = 24 * 60 * 60 * 1000L // 24 hours
        private const val API_TOKEN_DURATION_MILLIS = 5 * 60 * 1000L // 5 minutes
        private const val MAX_ACTIVE_API_TOKENS = 10

        @Volatile
        private var instance: SessionManager? = null

